always_comb begin
  data_n = data_q;
  if (in_valid) data_n = in_data;
end

always_ff @(posedge clk) begin
  data_q <= data_n;
end

always_comb begin
  data_n = data_q;  // latch previous value
  out_valid = 0;
  if (in_valid) begin
    data_n = in_data;
    out_valid = 1;
  end
end
